mapper.select:
SELECT
, lm.ID AS learningModelId , lm.LEARN_NAME FROM BILL_INPUT bi LEFT JOIN BILL_OUTPUT bo ON bi.TXBL_SRN = bo.TXBL_SRN AND bi.BASE_YM = bo.BASE_YM AND bi.BRCD = bo.BRCD LEFT JOIN LEARNING_MODEL lm ON bo.LEARNING_MODEL_ID = lm.ID WHERE bi.BRCD IS NOT NULL
AND bi.TXBL_SRN = #{txblSrn} AND bi.BASE_YM = #{baseYm} AND bi.BRCD = #{brcd}
AND bi.NO = #{no}
